// storage.js
export const SESSION_KEY = 'user_data';

export function save(data) {
  localStorage.setItem(SESSION_KEY, JSON.stringify(data));
}

export default class UserStorage {
  clear() { localStorage.clear(); }
}

// main.js
import UserStorage, { save, SESSION_KEY } from './storage.js';
const store = new UserStorage();
save({ id: 1 });
console.log('Using key:', SESSION_KEY);

codeExample2.code:
// heavyCalculator.js
export const calculate = (num) => num ** 10;

// app.js
const btn = document.querySelector('#calc-btn');

btn.addEventListener('click', async () => {
  try {
    // Only downloads heavyCalculator.js when user clicks
    const module = await import('./heavyCalculator.js');
    const result = module.calculate(2);
    console.log('Result:', result);
  } catch (err) {
    console.error('Module failed to load', err);
  }
});

